// Script Continued Below
var client_tasker_User_Form_Preferences = Class.create();
client_tasker_User_Form_Preferences.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

	// Returns the portal, page and view preferences for a task
	get_URL_Properties_for_Task_Based_on_Prefrences: function(){
		var sys_id = this.getParameter('sysparam_sys_id');
		var current_view = this.getParameter('sysparam_current_view');

		var oUserPref = new tasker_User_Form_Preferences();
		var url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(sys_id,current_view);
		return JSON.stringify(url_Properties);
	},

	// Returns the portal, page and view preferences for a task
	get_URL_for_Task_Based_on_Prefrences: function(){
		var taskerTable = 'x_153465_discovert_route_task_instance';
		var sys_id = this.getParameter('sysparam_sys_id');
		var current_view = this.getParameter('sysparam_current_view');

		var oUserPref = new tasker_User_Form_Preferences();
		var url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(sys_id,current_view);

		var task_url;
		task_url =  
			'../' + url_Properties.portal_url_ref + 
			'?id=' + url_Properties.pageId + 
			'&table=' + taskerTable + 
			'&sys_id=' + sys_id +
			'&view=' + url_Properties.view;

		return task_url;
	},	
	suggestedTaskGetRedirectURL: function(){
		var taskerTable = 'x_153465_discovert_route_task_instance';
		var suggested_task_number = this.getParameter("suggested_task_sys_id");
		var gr = new GlideRecord(taskerTable);
		gr.addQuery('suggested_task',suggested_task_number);
		gr.query();

		var new_task_url;

		if(gr.next()){
			var new_task_id = gr.sys_id;

			var oUserPref = new x_153465_discovert.tasker_User_Form_Preferences();
			var userPreferences = oUserPref.loadMyFormPreferences();
			var url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(gr.sys_id,'sp');

			new_task_url =  
				'../' + url_Properties.portal_url_ref + 
				'?id=' + url_Properties.pageId +
				'&table=' + taskerTable + 
				"&sys_id="+ new_task_id+ "&spa=1 target=_top";
		}
		return new_task_url;
	},

	type: 'client_tasker_User_Form_Preferences'
});
